jQuery.Class("Settings_Users_SwitchUsers_Js",{},{registerAdd:function(e){var t=this;e.find(".addItem").click(function(s){var i=[];e.find(".switchUsersTable tbody tr").each(function(e){i.push({user:$(this).find(".sufrom").val()})});var n=parseInt(e.find("#suCount").val())+1,r=($(s.currentTarget),e.find(".cloneItem tbody").clone(!0,!0));r.find(".sufrom option").each(function(e,t){$.each(i,function(e,s){$(t).val()==s.user&&r.find(t).remove()})}),r.find("tr").attr("data-id",n).addClass("row"+n),e.find(".switchUsersTable tbody").append(r.html()),e.find("#suCount").val(n),t.registerDelete(e.find("tr.row"+n)),app.showSelect2ElementView(e.find("tr.row"+n).find("select"))})},registerDelete:function(e){e.find(".delate").click(function(e){$(e.currentTarget).closest("tr").remove()})},registerSave:function(e){e.find(".saveItems").click(function(t){var s=[];e.find(".switchUsersTable tbody tr").each(function(e){$(this).find(".suto :selected").length>0&&s.push({user:$(this).find(".sufrom").val(),access:$(this).find(".suto").val()})}),app.saveAjax("saveSwitchUsers",s).then(function(e){Settings_Vtiger_Index_Js.showMessage({type:"success",text:e.result.message})})})},registerEvents:function(){var e=$(".contentsDiv");this.registerAdd(e),this.registerDelete(e),this.registerSave(e)}});